+  it("prefers a runtime avatar URL over non-URL identity avatars", () => {
+    expect(
+      resolveAgentAvatarUrl({ identity: { avatar: "A", avatarUrl: "/avatar/main" } }, {
+        avatar: "A",
+      } as { avatar: string }),
+    ).toBe("/avatar/main");
+  });
